CREATE TABLE IF NOT EXISTS `t_statement_detail` (
  `statement_detail_id` bigint NOT NULL auto_increment,
  `statement_id` bigint NOT NULL DEFAULT 0,
  `report_id` bigint NULL,
  `character_code` varchar(16) NOT NULL,
  `key_id` bigint NOT NULL,
  `month` varchar(6) NOT NULL,
  `plat_code` varchar(32) NOT NULL,
  `module_code` varchar(32) NULL,
  `statistic_method_code` varchar(32) NULL,
  `billing_service_code` varchar(64) NULL,
  `price` decimal(12,4) NULL,
  `actual_charge` decimal(12,4) NULL,
  `module_count` decimal(10,2) NULL,
  `module_free_count` decimal(10,2) NOT NULL,
  `contract_free_count` decimal(10,2) NOT NULL,
  `oa_customer_id` varchar(45) NULL,
  `currency` varchar(3) NOT NULL,
  `module_amount` decimal(12,4) NOT NULL,
  `contract_uuid` bigint NOT NULL,
  `contract_module_id` bigint NULL,
  `status` tinyint(1) NOT NULL,
  `bill_id` bigint NULL,
  `notify_oa_time` bigint NULL,
  `sign_entity_id` varchar(32) NOT NULL,
  `notify_oa_flag` tinyint(1) NOT NULL DEFAULT 0,
  `settlement_remark` varchar(256) NULL,
  `remark` varchar(255) NULL,
  `cre_time` bigint NULL,
  `upd_time` bigint NULL,
  `usd_exchange_amount` decimal(12,4) NULL,
  `usd_exchange_rate` float NULL,
  `usd_exchange_rate_id` varchar(32) NULL,
  KEY `I_BILL` (`bill_id`),
  KEY `I_CHARACTER` (`character_code`, `key_id`),
  KEY `I_MONTH` (`month`),
  KEY `I_REPOROT_ID` (`report_id`),
  PRIMARY KEY (`statement_detail_id`),
  UNIQUE KEY `U_MOUDLE` (`character_code`, `key_id`, `module_code`, `month`, `statistic_method_code`)
);

CREATE OR REPLACE VIEW `view_report_month_detail` AS select `a`.`report_month_detail_id` AS `report_month_detail_id`,`a`.`character_code` AS `character_code`,`a`.`key_id` AS `key_id`,`a`.`report_id` AS `report_id`,`a`.`plat_code` AS `plat_code`,`a`.`module_code` AS `module_code`,`a`.`org_id` AS `org_id`,`a`.`statistic_month` AS `statistic_month`,`a`.`statistic_count` AS `statistic_count`,`a`.`free_count` AS `free_count`,`a`.`statistic_method_code` AS `statistic_method_code`,`a`.`statement_detail_id` AS `statement_detail_id`,`a`.`cre_time` AS `cre_time`,`a`.`detail_file_path` AS `detail_file_path` from (`flycare`.`t_report_month_detail` `a` join `flycare`.`t_report` `b`) where ((`a`.`report_id` = `b`.`report_id`) and (`b`.`confirm_state` <> 4));
CREATE OR REPLACE VIEW `view_statement_detail` AS select `a`.`month` AS `statistic_month`,substr(`a`.`month`,1,4) AS `statistic_year`,`a`.`character_code` AS `character_code`,`a`.`key_id` AS `key_id`,`a`.`plat_code` AS `plat_code`,`a`.`billing_service_code` AS `billing_service_code`,`a`.`module_amount` AS `module_amount`,`a`.`usd_exchange_amount` AS `usd_exchange_amount`,`a`.`bill_id` AS `bill_id`,`a`.`sign_entity_id` AS `sign_entity_id`,(period_diff(date_format(now(),'%Y%m'),`a`.`month`) - 1) AS `overdueMonth`,`a`.`contract_uuid` AS `contract_uuid`,`a`.`cre_time` AS `cre_time` from `flycare`.`t_statement_detail` `a`;

