CREATE TABLE IF NOT EXISTS `t_params_template` (
  `id_params_template` bigint unsigned NOT NULL auto_increment,
  `name` varchar(45) NOT NULL,
  `app_name` varchar(255) NOT NULL,
  `app_package_name` varchar(255) NOT NULL,
  `description` varchar(200) NULL,
  `entry` bigint unsigned NULL,
  `create_time` datetime NOT NULL,
  `update_time` datetime NULL,
  `oid` varchar(64) NOT NULL,
  `file_type` tinyint NULL DEFAULT 1,
  UNIQUE KEY `IDX_PARAMS_TEMPLATE` (`oid`, `name`, `app_package_name`),
  PRIMARY KEY (`id_params_template`)
);

CREATE TABLE IF NOT EXISTS `qrtz_job_details` (
  `SCHED_NAME` varchar(120) NOT NULL,
  `JOB_NAME` varchar(200) NOT NULL,
  `JOB_GROUP` varchar(200) NOT NULL,
  `DESCRIPTION` varchar(250) NULL,
  `JOB_CLASS_NAME` varchar(250) NOT NULL,
  `IS_DURABLE` varchar(1) NOT NULL,
  `IS_NONCONCURRENT` varchar(1) NOT NULL,
  `IS_UPDATE_DATA` varchar(1) NOT NULL,
  `REQUESTS_RECOVERY` varchar(1) NOT NULL,
  `JOB_DATA` blob NULL,
  KEY `IDX_QRTZ_J_GRP` (`SCHED_NAME`, `JOB_GROUP`),
  KEY `IDX_QRTZ_J_REQ_RECOVERY` (`SCHED_NAME`, `REQUESTS_RECOVERY`),
  PRIMARY KEY (`SCHED_NAME`, `JOB_NAME`, `JOB_GROUP`)
);

CREATE TABLE IF NOT EXISTS `qrtz_blob_triggers` (
  `SCHED_NAME` varchar(120) NOT NULL,
  `TRIGGER_NAME` varchar(200) NOT NULL,
  `TRIGGER_GROUP` varchar(200) NOT NULL,
  `BLOB_DATA` blob NULL,
  PRIMARY KEY (`SCHED_NAME`, `TRIGGER_NAME`, `TRIGGER_GROUP`),
  KEY `SCHED_NAME` (`SCHED_NAME`, `TRIGGER_NAME`, `TRIGGER_GROUP`),
  CONSTRAINT `qrtz_blob_triggers_ibfk_1` FOREIGN KEY (`SCHED_NAME`, `TRIGGER_NAME`, `TRIGGER_GROUP`) REFERENCES `qrtz_triggers` (`SCHED_NAME`, `TRIGGER_NAME`, `TRIGGER_GROUP`) ON DELETE NO ACTION ON UPDATE NO ACTION
);

CREATE TABLE IF NOT EXISTS `t_param_job_detail` (
  `id` bigint NOT NULL auto_increment,
  `job_id` bigint NOT NULL,
  `flow_id` bigint NULL,
  `template_id` bigint NOT NULL,
  `app_package_name` varchar(255) NULL,
  `dev_sn` varchar(32) NULL,
  `status` int NOT NULL,
  `cre_time` datetime NOT NULL,
  `upd_time` datetime NULL,
  UNIQUE KEY `IDX_JOB_DETAIL` (`job_id`, `dev_sn`, `app_package_name`),
  PRIMARY KEY (`id`)
);

CREATE TABLE IF NOT EXISTS `t_params_template_entity` (
  `id_params_template_entity` bigint unsigned NOT NULL auto_increment,
  `name` varchar(45) NOT NULL,
  `description` varchar(200) NULL,
  `params_template` bigint NULL,
  `table_entity_entry` bigint NULL,
  `version` int NOT NULL,
  `create_time` datetime NOT NULL,
  `update_time` datetime NULL,
  PRIMARY KEY (`id_params_template_entity`)
);

CREATE TABLE IF NOT EXISTS `qrtz_simple_triggers` (
  `SCHED_NAME` varchar(120) NOT NULL,
  `TRIGGER_NAME` varchar(200) NOT NULL,
  `TRIGGER_GROUP` varchar(200) NOT NULL,
  `REPEAT_COUNT` bigint NOT NULL,
  `REPEAT_INTERVAL` bigint NOT NULL,
  `TIMES_TRIGGERED` bigint NOT NULL,
  PRIMARY KEY (`SCHED_NAME`, `TRIGGER_NAME`, `TRIGGER_GROUP`),
  CONSTRAINT `qrtz_simple_triggers_ibfk_1` FOREIGN KEY (`SCHED_NAME`, `TRIGGER_NAME`, `TRIGGER_GROUP`) REFERENCES `qrtz_triggers` (`SCHED_NAME`, `TRIGGER_NAME`, `TRIGGER_GROUP`) ON DELETE NO ACTION ON UPDATE NO ACTION
);

CREATE TABLE IF NOT EXISTS `t_table_entity` (
  `id_table_entity` bigint unsigned NOT NULL auto_increment,
  `table_schema` bigint unsigned NOT NULL,
  `name` varchar(45) NOT NULL,
  `org_id` bigint NOT NULL,
  `org_name` varchar(64) NOT NULL,
  `create_time` datetime NOT NULL,
  `update_time` datetime NULL,
  KEY `IDEX_TABLE_ENTITY_TABLE_SCHEMA` (`table_schema`),
  PRIMARY KEY (`id_table_entity`)
);

CREATE TABLE IF NOT EXISTS `t_role` (
  `role_id` bigint NOT NULL auto_increment,
  `role_name` varchar(45) NOT NULL,
  `role_remark` varchar(45) NULL,
  `cre_time` datetime NOT NULL,
  `upd_time` datetime NULL,
