-- ============================================================
CREATE DATABASE IF NOT EXISTS `ntms-mars`;
USE `ntms-mars`;

CREATE TABLE IF NOT EXISTS `t_app_file` (
  `app_file_id` bigint unsigned NOT NULL auto_increment,
  `app_package_name` varchar(255) NULL,
  `app_name` varchar(255) NULL,
  `cre_time` datetime NOT NULL,
  `upd_time` datetime NULL,
  PRIMARY KEY (`app_file_id`)
);

CREATE TABLE IF NOT EXISTS `t_power_role_resource` (
  `power_role_resource_id` bigint NOT NULL auto_increment,
  `role_id` bigint NOT NULL,
  `permission_code` varchar(100) NULL,
  `cre_time` datetime NULL,
  `upd_time` datetime NULL,
  PRIMARY KEY (`power_role_resource_id`)
);

CREATE TABLE IF NOT EXISTS `t_param_job_detail` (
  `id` bigint NOT NULL auto_increment,
  `job_id` bigint NOT NULL,
  `flow_id` bigint NULL,
  `template_id` bigint NOT NULL,
  `app_package_name` varchar(255) NULL,
  `dev_sn` varchar(32) NULL,
  `status` int NOT NULL,
  `cre_time` datetime NOT NULL,
  `upd_time` datetime NULL,
  UNIQUE KEY `IDX_JOB_DETAIL` (`job_id`, `dev_sn`, `app_package_name`),
  PRIMARY KEY (`id`)
);

CREATE TABLE IF NOT EXISTS `t_param_file_flow` (
  `flow_id` bigint NOT NULL auto_increment,
  `template_id` bigint NOT NULL,
  `app_package_name` varchar(255) NULL,
  `app_name` varchar(255) NULL,
  `dev_sn` varchar(32) NULL,
  `content_sha1` varchar(160) NULL,
  `sha1` varchar(160) NULL,
  `version` bigint NOT NULL,
  `cre_time` datetime NOT NULL,
  `upd_time` datetime NULL,
  `release_time` datetime NULL,
  `terminal_update_time` datetime NULL,
  `app_update_time` datetime NULL,
  `status` int NULL,
  PRIMARY KEY (`flow_id`)
);

CREATE TABLE IF NOT EXISTS `t_param_schema` (
  `id_param_schema` bigint unsigned NOT NULL auto_increment,
  `NAME` varchar(64) NULL,
  `description` varchar(200) NULL,
  `parent` bigint unsigned NOT NULL,
  `key` varchar(64) NULL,
  `length` int NULL,
  `nullable` tinyint unsigned NOT NULL,
  `value_type` tinyint unsigned NOT NULL,
  `ref_table_schema` bigint unsigned NULL,
  `create_time` datetime NOT NULL,
  `update_time` datetime NULL,
  KEY `IDX_PARAM_SCHEMA_PARENT` (`parent`),
  UNIQUE KEY `IDX_PARAM_SCHEMA_PARENT_KEY` (`parent`, `key`),
  UNIQUE KEY `IDX_PARAM_SCHEMA_PARENT_NAME` (`parent`, `NAME`),
  PRIMARY KEY (`id_param_schema`)
);

CREATE TABLE IF NOT EXISTS `t_role` (
  `role_id` bigint NOT NULL auto_increment,
  `role_name` varchar(45) NOT NULL,
  `role_remark` varchar(45) NULL,
  `cre_time` datetime NOT NULL,
  `upd_time` datetime NULL,
  PRIMARY KEY (`role_id`)
);

CREATE TABLE IF NOT EXISTS `qrtz_triggers` (
  `SCHED_NAME` varchar(120) NOT NULL,
  `TRIGGER_NAME` varchar(200) NOT NULL,
  `TRIGGER_GROUP` varchar(200) NOT NULL,
  `JOB_NAME` varchar(200) NOT NULL,
  `JOB_GROUP` varchar(200) NOT NULL,
  `DESCRIPTION` varchar(250) NULL,
  `NEXT_FIRE_TIME` bigint NULL,
  `PREV_FIRE_TIME` bigint NULL,
  `PRIORITY` int NULL,
  `TRIGGER_STATE` varchar(16) NOT NULL,
  `TRIGGER_TYPE` varchar(8) NOT NULL,
  `START_TIME` bigint NOT NULL,
  `END_TIME` bigint NULL,
  `CALENDAR_NAME` varchar(200) NULL,
  `MISFIRE_INSTR` smallint NULL,
  `JOB_DATA` blob NULL,
  KEY `IDX_QRTZ_T_C` (`SCHED_NAME`, `CALENDAR_NAME`),
  KEY `IDX_QRTZ_T_G` (`SCHED_NAME`, `TRIGGER_GROUP`),
  KEY `IDX_QRTZ_T_J` (`SCHED_NAME`, `JOB_NAME`, `JOB_GROUP`),
  KEY `IDX_QRTZ_T_JG` (`SCHED_NAME`, `JOB_GROUP`),
  KEY `IDX_QRTZ_T_NEXT_FIRE_TIME` (`SCHED_NAME`, `NEXT_FIRE_TIME`),
  KEY `IDX_QRTZ_T_NFT_MISFIRE` (`SCHED_NAME`, `MISFIRE_INSTR`, `NEXT_FIRE_TIME`),
  KEY `IDX_QRTZ_T_NFT_ST` (`SCHED_NAME`, `TRIGGER_STATE`, `NEXT_FIRE_TIME`),
  KEY `IDX_QRTZ_T_NFT_ST_MISFIRE` (`SCHED_NAME`, `MISFIRE_INSTR`, `NEXT_FIRE_TIME`, `TRIGGER_STATE`),
  KEY `IDX_QRTZ_T_NFT_ST_MISFIRE_GRP` (`SCHED_NAME`, `MISFIRE_INSTR`, `NEXT_FIRE_TIME`, `TRIGGER_GROUP`, `TRIGGER_STATE`),
  KEY `IDX_QRTZ_T_N_G_STATE` (`SCHED_NAME`, `TRIGGER_GROUP`, `TRIGGER_STATE`),
  KEY `IDX_QRTZ_T_N_STATE` (`SCHED_NAME`, `TRIGGER_NAME`, `TRIGGER_GROUP`, `TRIGGER_STATE`),
  KEY `IDX_QRTZ_T_STATE` (`SCHED_NAME`, `TRIGGER_STATE`),
  PRIMARY KEY (`SCHED_NAME`, `TRIGGER_NAME`, `TRIGGER_GROUP`),
  CONSTRAINT `qrtz_triggers_ibfk_1` FOREIGN KEY (`SCHED_NAME`, `JOB_NAME`, `JOB_GROUP`) REFERENCES `qrtz_job_details` (`SCHED_NAME`, `JOB_NAME`, `JOB_GROUP`) ON DELETE NO ACTION ON UPDATE NO ACTION
);

CREATE TABLE IF NOT EXISTS `t_params_template` (
  `id_params_template` bigint unsigned NOT NULL auto_increment,
  `name` varchar(45) NOT NULL,
  `app_name` varchar(255) NOT NULL,
  `app_package_name` varchar(255) NOT NULL,
  `description` varchar(200) NULL,
  `entry` bigint unsigned NULL,
  `create_time` datetime NOT NULL,
  `update_time` datetime NULL,
  `oid` varchar(64) NOT NULL,
  `file_type` tinyint NULL DEFAULT 1,
  UNIQUE KEY `IDX_PARAMS_TEMPLATE` (`oid`, `name`, `app_package_name`),
  PRIMARY KEY (`id_params_template`)
);

CREATE TABLE IF NOT EXISTS `t_table_entity` (
  `id_table_entity` bigint unsigned NOT NULL auto_increment,
  `table_schema` bigint unsigned NOT NULL,
  `name` varchar(45) NOT NULL,
  `org_id` bigint NOT NULL,
  `org_name` varchar(64) NOT NULL,
  `create_time` datetime NOT NULL,
  `update_time` datetime NULL,
  KEY `IDEX_TABLE_ENTITY_TABLE_SCHEMA` (`table_schema`),
  PRIMARY KEY (`id_table_entity`)
);

CREATE TABLE IF NOT EXISTS `t_partner_info` (
  `partner_id` bigint NOT NULL auto_increment,
  `partner_code` varchar(32) NOT NULL,
  `partner_rsa_pub` varchar(3072) NOT NULL,
  `partner_desc` varchar(512) NULL,
  `cre_time` datetime NOT NULL,
  `upd_time` datetime NULL,
  PRIMARY KEY (`partner_id`)
);

CREATE TABLE IF NOT EXISTS `t_task` (
  `id` bigint NOT NULL auto_increment,
  `name` varchar(45) NOT NULL,
  `status` int NULL,
  `total_num` int NULL,
  `complete_num` int NULL,
  `percent` int NULL,
  `message` text NULL,
  `download_url` varchar(512) NULL,
  `start_time` datetime NOT NULL,
  `finish_time` datetime NULL,
  `cre_time` datetime NOT NULL,
  `cre_user` varchar(45) NULL,
  `oid` varchar(64) NOT NULL,
  PRIMARY KEY (`id`)
);

CREATE TABLE IF NOT EXISTS `qrtz_scheduler_state` (
  `SCHED_NAME` varchar(120) NOT NULL,
  `INSTANCE_NAME` varchar(200) NOT NULL,
  `LAST_CHECKIN_TIME` bigint NOT NULL,
  `CHECKIN_INTERVAL` bigint NOT NULL,
  PRIMARY KEY (`SCHED_NAME`, `INSTANCE_NAME`)
);

CREATE TABLE IF NOT EXISTS `t_device` (
  `dev_id` bigint NOT NULL auto_increment,
  `dev_sn` varchar(32) NULL,
  `cre_time` datetime NULL,
  `upd_time` datetime NULL,
  `org_id` bigint NOT NULL,
  `org_name` varchar(64) NOT NULL,
  PRIMARY KEY (`dev_id`),
  UNIQUE KEY `idx_device_sn_firmcode` (`dev_sn`)
);

CREATE TABLE IF NOT EXISTS `t_user` (
  `user_id` bigint NOT NULL auto_increment,
  `user_name` varchar(100) NOT NULL,
  `user_mobile` varchar(64) NOT NULL,
  `password` varchar(64) NULL,
  `user_status` tinyint NULL,
  `user_type` tinyint NOT NULL,
  `cre_time` datetime NULL,
  `upd_time` datetime NULL,
  `remark` varchar(255) NULL,
  `full_name` varchar(100) NULL,
  PRIMARY KEY (`user_id`),
  UNIQUE KEY `ux_user_username` (`user_name`)
);

CREATE TABLE IF NOT EXISTS `qrtz_cron_triggers` (
  `SCHED_NAME` varchar(120) NOT NULL,
  `TRIGGER_NAME` varchar(200) NOT NULL,
  `TRIGGER_GROUP` varchar(200) NOT NULL,
  `CRON_EXPRESSION` varchar(120) NOT NULL,
  `TIME_ZONE_ID` varchar(80) NULL,
  PRIMARY KEY (`SCHED_NAME`, `TRIGGER_NAME`, `TRIGGER_GROUP`),
  CONSTRAINT `qrtz_cron_triggers_ibfk_1` FOREIGN KEY (`SCHED_NAME`, `TRIGGER_NAME`, `TRIGGER_GROUP`) REFERENCES `qrtz_triggers` (`SCHED_NAME`, `TRIGGER_NAME`, `TRIGGER_GROUP`) ON DELETE NO ACTION ON UPDATE NO ACTION
);

CREATE TABLE IF NOT EXISTS `t_app_group` (
  `app_group_id` bigint NOT NULL auto_increment,
  `app_group_name` varchar(60) NOT NULL,
  `app_group_desc` varchar(255) NULL,
  `cre_time` datetime NOT NULL,
  `upd_time` datetime NULL,
  `org_id` bigint NOT NULL,
  PRIMARY KEY (`app_group_id`)
);

CREATE TABLE IF NOT EXISTS `t_user_org` (
  `user_org_id` bigint NOT NULL auto_increment,
  `user_name` varchar(100) NOT NULL,
  `org_id` bigint NOT NULL,
  `org_name` varchar(64) NULL,
  `cre_time` datetime NULL,
  `upd_time` datetime NULL,
  PRIMARY KEY (`user_org_id`),
  UNIQUE KEY `ux_user_org_userorg` (`user_name`, `org_id`)
);

CREATE TABLE IF NOT EXISTS `t_operator_config` (
  `operator_config_id` bigint NOT NULL auto_increment,
  `operator_id` bigint NOT NULL,
  `oid` varchar(64) NOT NULL,
  `param_key` varchar(100) NOT NULL,
  `param_value` varchar(100) NOT NULL,
  PRIMARY KEY (`operator_config_id`),
  UNIQUE KEY `U_OID_PARAM_KEY` (`oid`, `param_key`)
);

CREATE TABLE IF NOT EXISTS `qrtz_blob_triggers` (
  `SCHED_NAME` varchar(120) NOT NULL,
  `TRIGGER_NAME` varchar(200) NOT NULL,
  `TRIGGER_GROUP` varchar(200) NOT NULL,
  `BLOB_DATA` blob NULL,
  PRIMARY KEY (`SCHED_NAME`, `TRIGGER_NAME`, `TRIGGER_GROUP`),
  KEY `SCHED_NAME` (`SCHED_NAME`, `TRIGGER_NAME`, `TRIGGER_GROUP`),
  CONSTRAINT `qrtz_blob_triggers_ibfk_1` FOREIGN KEY (`SCHED_NAME`, `TRIGGER_NAME`, `TRIGGER_GROUP`) REFERENCES `qrtz_triggers` (`SCHED_NAME`, `TRIGGER_NAME`, `TRIGGER_GROUP`) ON DELETE NO ACTION ON UPDATE NO ACTION
);

CREATE TABLE IF NOT EXISTS `qrtz_job_details` (
  `SCHED_NAME` varchar(120) NOT NULL,
  `JOB_NAME` varchar(200) NOT NULL,
  `JOB_GROUP` varchar(200) NOT NULL,
  `DESCRIPTION` varchar(250) NULL,
  `JOB_CLASS_NAME` varchar(250) NOT NULL,
  `IS_DURABLE` varchar(1) NOT NULL,
  `IS_NONCONCURRENT` varchar(1) NOT NULL,
  `IS_UPDATE_DATA` varchar(1) NOT NULL,
  `REQUESTS_RECOVERY` varchar(1) NOT NULL,
  `JOB_DATA` blob NULL,
  KEY `IDX_QRTZ_J_GRP` (`SCHED_NAME`, `JOB_GROUP`),
  KEY `IDX_QRTZ_J_REQ_RECOVERY` (`SCHED_NAME`, `REQUESTS_RECOVERY`),
  PRIMARY KEY (`SCHED_NAME`, `JOB_NAME`, `JOB_GROUP`)
);

CREATE TABLE IF NOT EXISTS `t_table_entity_audit` (
  `id_table_entity` bigint unsigned NOT NULL auto_increment,
  `table_schema` bigint unsigned NOT NULL,
  `name` varchar(45) NOT NULL,
  `audit_id` bigint unsigned NOT NULL,
  `org_id` bigint NOT NULL,
  `org_name` varchar(64) NOT NULL,
  `create_time` datetime NOT NULL,
  `update_time` datetime NULL,
  KEY `IDEX_TABLE_ENTITY_TABLE_SCHEMA` (`table_schema`),
  PRIMARY KEY (`id_table_entity`)
);

CREATE TABLE IF NOT EXISTS `t_param_entity_audit` (
  `audit_id` bigint unsigned NOT NULL auto_increment,
  `app_name` varchar(255) NOT NULL,
  `app_package_name` varchar(255) NOT NULL,
  `table_schema_name` varchar(255) NOT NULL,
  `id_table_entity` bigint unsigned NOT NULL,
  `entity_name` varchar(255) NOT NULL,
  `oid` varchar(64) NOT NULL,
  `org_id` bigint NOT NULL,
  `org_name` varchar(64) NOT NULL,
  `applicant` varchar(64) NOT NULL,
  `auditor` varchar(64) NULL,
  `operation_type` tinyint unsigned NOT NULL,
  `action` tinyint unsigned NOT NULL,
  `status` tinyint unsigned NOT NULL,
  `remark` varchar(510) NULL,
  `create_time` datetime NOT NULL,
  `update_time` datetime NULL,
  PRIMARY KEY (`audit_id`)
);

CREATE TABLE IF NOT EXISTS `t_org` (
  `org_id` bigint NOT NULL auto_increment,
  `org_name` varchar(45) NOT NULL,
  `org_desc` varchar(200) NULL,
  `parent_id` bigint NOT NULL,
  `cre_time` datetime NOT NULL,
  `upd_time` datetime NULL,
  PRIMARY KEY (`org_id`)
);

CREATE TABLE IF NOT EXISTS `qrtz_calendars` (
  `SCHED_NAME` varchar(120) NOT NULL,
  `CALENDAR_NAME` varchar(200) NOT NULL,
  `CALENDAR` blob NOT NULL,
  PRIMARY KEY (`SCHED_NAME`, `CALENDAR_NAME`)
);

CREATE TABLE IF NOT EXISTS `t_notification` (
  `id` bigint NOT NULL auto_increment,
  `content` text NULL,
  `level` int NULL,
  `status` int NULL,
  `cre_time` datetime NOT NULL,
  `upd_time` datetime NULL,
  `cre_user` varchar(45) NULL,
  `oid` varchar(64) NOT NULL,
  PRIMARY KEY (`id`)
);

CREATE TABLE IF NOT EXISTS `t_default_param_management_audit` (
  `id_default_param_management` bigint unsigned NOT NULL auto_increment,
  `parent` bigint unsigned NOT NULL,
  `param_schema` bigint unsigned NOT NULL,
  `default_value` bigint unsigned NOT NULL,
  `operation` tinyint unsigned NOT NULL,
  `create_time` datetime NOT NULL,
  `update_time` datetime NULL,
  UNIQUE KEY `IDX_DEFT_PARAM_MM_PARENT_DEFAULT_VALUE` (`parent`, `default_value`),
  PRIMARY KEY (`id_default_param_management`)
);

CREATE TABLE IF NOT EXISTS `t_app_template_ref` (
  `app_template_id` bigint NOT NULL auto_increment,
  `template_id` bigint NOT NULL,
  `app_package_name` varchar(255) NULL,
  `app_name` varchar(255) NULL,
  `cre_time` datetime NOT NULL,
  `upd_time` datetime NULL,
  `template_modify_mark` tinyint NULL DEFAULT 0,
  PRIMARY KEY (`app_template_id`)
);

CREATE TABLE IF NOT EXISTS `qrtz_simprop_triggers` (
  `SCHED_NAME` varchar(120) NOT NULL,
  `TRIGGER_NAME` varchar(200) NOT NULL,
  `TRIGGER_GROUP` varchar(200) NOT NULL,
  `STR_PROP_1` varchar(512) NULL,
  `STR_PROP_2` varchar(512) NULL,
  `STR_PROP_3` varchar(512) NULL,
  `INT_PROP_1` int NULL,
  `INT_PROP_2` int NULL,
  `LONG_PROP_1` bigint NULL,
  `LONG_PROP_2` bigint NULL,
  `DEC_PROP_1` decimal(13,4) NULL,
  `DEC_PROP_2` decimal(13,4) NULL,
  `BOOL_PROP_1` varchar(1) NULL,
  `BOOL_PROP_2` varchar(1) NULL,
  PRIMARY KEY (`SCHED_NAME`, `TRIGGER_NAME`, `TRIGGER_GROUP`),
  CONSTRAINT `qrtz_simprop_triggers_ibfk_1` FOREIGN KEY (`SCHED_NAME`, `TRIGGER_NAME`, `TRIGGER_GROUP`) REFERENCES `qrtz_triggers` (`SCHED_NAME`, `TRIGGER_NAME`, `TRIGGER_GROUP`) ON DELETE NO ACTION ON UPDATE NO ACTION
);

CREATE TABLE IF NOT EXISTS `t_default_param_management` (
  `id_default_param_management` bigint unsigned NOT NULL auto_increment,
  `parent` bigint unsigned NOT NULL,
  `param_schema` bigint unsigned NOT NULL,
  `default_value` bigint unsigned NOT NULL,
  `operation` tinyint unsigned NOT NULL,
  `create_time` datetime NOT NULL,
  `update_time` datetime NULL,
  UNIQUE KEY `IDX_DEFT_PARAM_MM_PARENT_DEFAULT_VALUE` (`parent`, `default_value`),
  PRIMARY KEY (`id_default_param_management`)
);

CREATE TABLE IF NOT EXISTS `t_path` (
  `id` bigint unsigned NOT NULL auto_increment,
  `parent_id` bigint NOT NULL,
  `folder_name` varchar(64) NOT NULL,
  `parent_path` varchar(1024) NULL,
  `oid` varchar(64) NOT NULL,
  `cre_time` datetime NOT NULL,
  KEY `IDX_PATH` (`oid`),
  PRIMARY KEY (`id`)
);

CREATE TABLE IF NOT EXISTS `t_param_file_release` (
  `id` bigint NOT NULL auto_increment,
  `template_id` bigint NOT NULL,
  `app_package_name` varchar(255) NULL,
  `app_name` varchar(255) NULL,
  `dev_sn` varchar(32) NULL,
  `sha1` varchar(160) NULL,
  `version` bigint NOT NULL,
  `cre_time` datetime NOT NULL,
  `upd_time` datetime NULL,
  `release_time` datetime NULL,
  `terminal_update_time` datetime NULL,
  `app_update_time` datetime NULL,
  `status` int NULL,
  PRIMARY KEY (`id`)
);

CREATE TABLE IF NOT EXISTS `t_attach` (
  `id` bigint unsigned NOT NULL auto_increment,
  `path_id` bigint NOT NULL,
  `file_name` varchar(128) NOT NULL,
  `file_size` int NULL,
  `file_type` varchar(32) NULL,
  `oid` varchar(64) NOT NULL,
  `org_id` bigint NOT NULL,
  `org_name` varchar(64) NOT NULL,
  `cre_time` datetime NOT NULL,
  UNIQUE KEY `IDX_OID_PATH_NAME` (`path_id`, `file_name`, `oid`),
  PRIMARY KEY (`id`)
);

CREATE TABLE IF NOT EXISTS `t_param_job` (
  `job_id` bigint NOT NULL auto_increment,
  `job_uuid` varchar(32) NULL,
  `job_name` varchar(255) NULL,
  `job_mode` int NOT NULL,
  `oid` varchar(64) NOT NULL,
  `org_id` bigint NOT NULL,
  `org_name` varchar(64) NULL,
  `job_desc` varchar(255) NULL,
  `job_status` int NOT NULL,
  `is_cancel` int NULL DEFAULT 0,
  `is_bind` int NOT NULL DEFAULT 0,
  `cre_time` datetime NOT NULL,
  `upd_time` datetime NULL,
  KEY `IDX_JOB_OID_ORGID_NAME` (`oid`, `org_id`, `job_name`),
  PRIMARY KEY (`job_id`)
);

CREATE TABLE IF NOT EXISTS `t_partner_ram_account` (
  `id` bigint NOT NULL auto_increment,
  `user_name` varchar(100) NOT NULL,
  `access_key` varchar(16) NOT NULL,
  `security_key` varchar(64) NOT NULL,
  `link_source` varchar(32) NULL,
  `cre_time` datetime NULL,
  `upd_time` datetime NULL,
  PRIMARY KEY (`id`)
);

CREATE TABLE IF NOT EXISTS `t_power_resource` (
  `power_resource_id` bigint NOT NULL auto_increment,
  `resource_name` varchar(50) NOT NULL,
  `resource_type` tinyint NOT NULL,
  `priority` int NULL,
  `resource_icon` varchar(64) NULL,
  `resource_url` varchar(255) NULL,
  `parent_id` bigint NULL,
  `permission_code` varchar(128) NULL,
  `resource_status` tinyint NOT NULL,
  `cre_time` datetime NOT NULL,
  `upd_time` datetime NULL,
  PRIMARY KEY (`power_resource_id`),
  UNIQUE KEY `uk_idx_resource_permission_code` (`permission_code`)
);

CREATE TABLE IF NOT EXISTS `qrtz_fired_triggers` (
  `SCHED_NAME` varchar(120) NOT NULL,
  `ENTRY_ID` varchar(95) NOT NULL,
  `TRIGGER_NAME` varchar(200) NOT NULL,
  `TRIGGER_GROUP` varchar(200) NOT NULL,
  `INSTANCE_NAME` varchar(200) NOT NULL,
  `FIRED_TIME` bigint NOT NULL,
  `SCHED_TIME` bigint NOT NULL,
  `PRIORITY` int NOT NULL,
  `STATE` varchar(16) NOT NULL,
  `JOB_NAME` varchar(200) NULL,
  `JOB_GROUP` varchar(200) NULL,
  `IS_NONCONCURRENT` varchar(1) NULL,
  `REQUESTS_RECOVERY` varchar(1) NULL,
  KEY `IDX_QRTZ_FT_INST_JOB_REQ_RCVRY` (`SCHED_NAME`, `INSTANCE_NAME`, `REQUESTS_RECOVERY`),
  KEY `IDX_QRTZ_FT_JG` (`SCHED_NAME`, `JOB_GROUP`),
  KEY `IDX_QRTZ_FT_J_G` (`SCHED_NAME`, `JOB_NAME`, `JOB_GROUP`),
  KEY `IDX_QRTZ_FT_TG` (`SCHED_NAME`, `TRIGGER_GROUP`),
  KEY `IDX_QRTZ_FT_TRIG_INST_NAME` (`SCHED_NAME`, `INSTANCE_NAME`),
  KEY `IDX_QRTZ_FT_T_G` (`SCHED_NAME`, `TRIGGER_NAME`, `TRIGGER_GROUP`),
  PRIMARY KEY (`SCHED_NAME`, `ENTRY_ID`)
);

CREATE TABLE IF NOT EXISTS `t_param_layout` (
  `id_param_layout` bigint unsigned NOT NULL auto_increment,
  `param_id` bigint NULL,
  `parent` bigint NOT NULL,
  `x` int NOT NULL,
  `y` int NOT NULL,
  `w` int NOT NULL,
  `h` int NOT NULL,
  `type` tinyint NOT NULL,
  `create_time` datetime NOT NULL,
  `update_time` datetime NULL,
  PRIMARY KEY (`id_param_layout`)
);

CREATE TABLE IF NOT EXISTS `t_param_value` (
  `id_param_value` bigint unsigned NOT NULL auto_increment,
  `parent` bigint unsigned NOT NULL,
  `param_schema` bigint unsigned NOT NULL,
  `param_type` tinyint unsigned NOT NULL,
  `string_value` varchar(255) NULL,
  `boolean_value` tinyint unsigned NULL,
  `blob_value` tinyblob NULL,
  `ref_table_schema` bigint unsigned NULL,
  `ref_table_entity` bigint unsigned NULL,
  `create_time` datetime NOT NULL,
  `update_time` datetime NULL,
  KEY `IDX_PARAM_VALUE_PARENT_PARAM_SCHEMA` (`parent`, `param_schema`),
  PRIMARY KEY (`id_param_value`)
);

CREATE TABLE IF NOT EXISTS `t_app_group_detail` (
  `app_group_detail_id` bigint NOT NULL auto_increment,
  `app_group_id` bigint NOT NULL,
  `app_group_name` varchar(60) NOT NULL,
  `app_name` varchar(255) NULL,
  `app_package_name` varchar(255) NOT NULL,
  `cre_time` datetime NOT NULL,
  `upd_time` datetime NULL,
  `app_file_id` bigint NOT NULL,
  PRIMARY KEY (`app_group_detail_id`),
  KEY `idx_appgrpdt_bidpkg` (`app_package_name`),
  KEY `idx_appgrpdt_grpid` (`app_group_id`)
);

CREATE TABLE IF NOT EXISTS `qrtz_paused_trigger_grps` (
  `SCHED_NAME` varchar(120) NOT NULL,
  `TRIGGER_GROUP` varchar(200) NOT NULL,
  PRIMARY KEY (`SCHED_NAME`, `TRIGGER_GROUP`)
);

CREATE TABLE IF NOT EXISTS `t_table_schema` (
  `id_table_schema` bigint unsigned NOT NULL auto_increment,
  `name` varchar(45) NOT NULL,
  `description` varchar(200) NULL,
  `parent` bigint unsigned NOT NULL,
  `create_time` datetime NOT NULL,
  `update_time` datetime NULL,
  UNIQUE KEY `IDX_TABLE_SCHEMA_PARENT_AND_NAME` (`parent`, `name`),
  PRIMARY KEY (`id_table_schema`)
);

CREATE TABLE IF NOT EXISTS `t_param_entity_audit_history` (
  `audit_history_id` bigint unsigned NOT NULL auto_increment,
  `audit_id` bigint unsigned NOT NULL,
  `from` varchar(64) NOT NULL,
  `to` varchar(64) NOT NULL,
  `status` tinyint unsigned NOT NULL,
  `remark` varchar(510) NULL,
  `create_time` datetime NOT NULL,
  `update_time` datetime NULL,
  PRIMARY KEY (`audit_history_id`)
);

CREATE TABLE IF NOT EXISTS `qrtz_simple_triggers` (
  `SCHED_NAME` varchar(120) NOT NULL,
  `TRIGGER_NAME` varchar(200) NOT NULL,
  `TRIGGER_GROUP` varchar(200) NOT NULL,
  `REPEAT_COUNT` bigint NOT NULL,
  `REPEAT_INTERVAL` bigint NOT NULL,
  `TIMES_TRIGGERED` bigint NOT NULL,
  PRIMARY KEY (`SCHED_NAME`, `TRIGGER_NAME`, `TRIGGER_GROUP`),
  CONSTRAINT `qrtz_simple_triggers_ibfk_1` FOREIGN KEY (`SCHED_NAME`, `TRIGGER_NAME`, `TRIGGER_GROUP`) REFERENCES `qrtz_triggers` (`SCHED_NAME`, `TRIGGER_NAME`, `TRIGGER_GROUP`) ON DELETE NO ACTION ON UPDATE NO ACTION
);

