CREATE OR REPLACE VIEW `view_strategy` AS select `ts`.`strategy_id` AS `strategy_id`,`ts`.`strategy_name` AS `strategy_name`,`ts`.`plat_code` AS `plat_code`,`ts`.`character_code` AS `character_code`,`ts`.`key_id` AS `key_id`,`ts`.`org_id` AS `org_id`,`ts`.`notify_temp_id` AS `notify_temp_id`,`ts`.`warning_model_id` AS `warning_model_id`,`ts`.`strategy_threshold` AS `strategy_threshold`,`ts`.`email_notify_flag` AS `email_notify_flag`,`ts`.`inner_notify_flag` AS `inner_notify_flag`,`ts`.`timezone` AS `timezone`,`ts`.`target_bind_method` AS `target_bind_method`,date_format(from_unixtime(`ts`.`cre_time`),'%Y%m%d') AS `statistic_day`,date_format(from_unixtime(`ts`.`cre_time`),'%Y%m') AS `statistic_month`,date_format(from_unixtime(`ts`.`cre_time`),'%Y') AS `statistic_year`,`ts`.`cre_time` AS `cre_time`,`ts`.`upd_time` AS `upd_time` from `toms-mars`.`t_strategy` `ts`;
